Based on the reference materials and detailed specifications, here's the complete implementation of the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table names to corresponding struct types
  std::map<std::string, rfl::Type> table_map = {
    {"Student", Student},
    {"Course", Course},
    {"Score", Score},
    {"Major", Major}
  };

  // Get the appropriate type based on table name
  auto type_it = table_map.find(table_name);
  if (type_it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create table if not exists
  auto create_result = (sqlgen::create_table<T> | sqlgen::if_not_exists)(conn);
  if (!create_result) {
    throw std::runtime_error("Failed to create table");
  }

  // Insert records
  auto insert_result = sqlgen::insert(conn, records);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table names to corresponding struct types and primary key columns
  std::map<std::string, std::pair<rfl::Type, std::string>> table_map = {
    {"Student", {Student, "SNo"}},
    {"Course", {Course, "CID"}},
    {"Score", {Score, "ScID"}},
    {"Major", {Major, "MID"}}
  };

  auto type_it = table_map.find(table_name);
  if (type_it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  auto [RecordType, pk_col] = type_it->second;

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Build delete statement with where condition
  auto delete_stmt = sqlgen::delete_from<RecordType> | 
                    where(eval("id"_c == record_id));

  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    throw std::runtime_error("Failed to delete record");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
  // Map table names to corresponding struct types and primary key columns
  std::map<std::string, std::pair<rfl::Type, std::string>> table_map = {
    {"Student", {Student, "SNo"}},
    {"Course", {Course, "CID"}},
    {"Score", {Score, "ScID"}},
    {"Major", {Major, "MID"}}
  };

  auto type_it = table_map.find(table_name);
  if (type_it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  auto [RecordType, pk_col] = type_it->second;

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Build update statement
  auto update_stmt = sqlgen::update<RecordType>(
    set(eval(col_name + "_c") = new_value)
  ) | where(eval(pk_col + "_c") == record_id);

  auto update_result = update_stmt(conn);
  if (!update_result) {
    throw std::runtime_error("Failed to update record");
  }
}
```

## Key Implementation Details:

1. **Table Mapping**: Used a map to associate table names with their corresponding struct types and primary key columns.

2. **Database Connection**: Used `sqlgen::sqlite::connect()` to establish connection to the database.

3. **Table Creation**: Used `sqlgen::create_table<T> | sqlgen::if_not_exists` pattern to create tables if they don't exist.

4. **Record Insertion**: Used `sqlgen::insert()` function to insert records into the database.

5. **Delete Operation**: Used `sqlgen::delete_from<RecordType>` combined with `where()` condition to delete specific records.

6. **Update Operation**: Used `sqlgen::update<RecordType>()` with `set()` and `where()` clauses to modify specific fields.

7. **Error Handling**: Added proper error checking for database operations.

8. **Dynamic Column Handling**: Used `eval()` function to dynamically create column references from string names.

The implementation follows sqlgen's fluent API pattern and properly handles the different table structures and primary key types defined in the reference materials.

