```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto connection = conn_result.value();

    // 2. Drop the Product table if it exists
    auto drop_result = (sqlgen::drop<Product> | sqlgen::if_exists)(connection);
    if (!drop_result) {
        return false;
    }

    // 3. Create the Product table
    auto create_result = sqlgen::create_table<Product>(connection);
    if (!create_result) {
        return false;
    }

    // 4. Start a transaction
    auto begin_result = connection->begin_transaction();
    if (!begin_result) {
        return false;
    }

    // 5. Use sqlgen::write to insert products in batch
    auto write_result = sqlgen::write(products)(connection);
    if (!write_result) {
        // 6. Rollback if write fails
        connection->rollback();
        return false;
    }

    // 6. Commit if all inserts succeed
    auto commit_result = connection->commit();
    if (!commit_result) {
        connection->rollback();
        return false;
    }

    return true;
}

}  // namespace batch_insert_products
```

