  auto user_after_create_stmt = sqlgen::transpilation::to_create_table<UserAfter>();

  // 3. Extract column names from both CREATE TABLE statements
  std::set<std::string> existing_columns;
  for (const auto& col : user_create_stmt.columns) {
    existing_columns.insert(col.name);
  }

  std::set<std::string> new_columns;
