                                  Type2, Type3>{
      .operand1 = transpilation::to_transpilation_type(_str),
      .operand2 = transpilation::to_transpilation_type(_from),
      .operand3 = transpilation::to_transpilation_type(_to)};
}

template <class... Ts>
auto concat(const Ts&... _ts) {
  static_assert(sizeof...(_ts) > 0,
