 * This function demonstrates a LEFT JOIN.
 * Returns: std::string.
 */
inline std::string left_join_explicit() {
  using namespace sqlgen::literals;

  // Start query on User table with alias "u"
  auto query = sqlgen::select_from<User, "u">("id"_u, "name"_u)
              // Left join with Post table with alias "p" on u.id == p.user_id
